import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    command = input().strip()
    if not command:
        return "Error: Empty command"
    forbidden = [';', '|', '&', '<', '>', '(', ')', '[', ']', '{', '}', '$', '`']
    for c in forbidden:
        if c in command:
            return "Error: Invalid command"
    try:
        args = shlex.split(command)
    except ValueError:
        return "Error: Invalid command"
    result = subprocess.run(args, capture_output=True, text=True)
    return f"Command executed with return code {result.returncode}\nOutput:\n{result.stdout}\nError:\n{result.stderr}"

